// appsettings.json
{
  "Database": {
    "ConnectionString": "Server=localhost;Database=myapp;",
    "MaxPoolSize": 20
  }
}

// Override với environment variable
// Database:ConnectionString → Database__ConnectionString (dùng __ thay :)
// Linux: export Database__ConnectionString="Server=prod;..."
// Docker compose:
// environment:
//   - Database__ConnectionString=Server=prod;...
//   - Database__MaxPoolSize=50

// appsettings.Development.json override không-sensitive config
// {
//   "Database": { "MaxPoolSize": 5 }
// }

// Secret Manager (dev only, không commit)
// dotnet user-secrets set "Database:ConnectionString" "Server=local;..."

// Azure Key Vault (production)
if (!builder.Environment.IsDevelopment())
{
    builder.Configuration.AddAzureKeyVault(
        new Uri($"https://{builder.Configuration["KeyVault:Name"]}.vault.azure.net/"),
        new DefaultAzureCredential());
}

// Verify config order (debug)
foreach (var provider in ((IConfigurationRoot)builder.Configuration).Providers)
    Console.WriteLine($"Provider: {provider.GetType().Name}");
